  // Perform an action invocation (dispatches to action sub via actionsTable)
  static async performAction(state: GameState, io: GameIO, actionNum: number, nounVal?: number, secondVal?: number): Promise<[GameState, InformValue]> {
    // Save inp1/inp2 before overwriting (R_Process pattern)
    const savedInp1 = getGlobal(state, 'inp1');
    const savedInp2 = getGlobal(state, 'inp2');
    state = setGlobal(state, 'action', actionNum);
    if (nounVal !== undefined) {
      state = setGlobal(state, 'noun', nounVal);
      state = setGlobal(state, 'inp1', nounVal);
    }
    if (secondVal !== undefined) {
      state = setGlobal(state, 'second', secondVal);
      state = setGlobal(state, 'inp2', secondVal);
    }
    // Look up action routine in actionsTable
    const at = state.definition.actionsTable;
    if (actionNum >= 0 && actionNum < at.length) {
      const ref = at[actionNum];
      if (ref !== null && ref !== undefined && typeof ref === 'object' && 'kind' in ref && ref.kind === 'routine') {
        const [rs, rv] = await Game.invokeRoutine((ref as any).routineName, state, io, []);
        state = rs;
        if (nounVal !== undefined) state = setGlobal(state, 'inp1', savedInp1);
        if (secondVal !== undefined) state = setGlobal(state, 'inp2', savedInp2);
        return [state, rv];
      }
    }
    return [state, intValue(0)];
  }

  // Process an action statement (compiler veneer, like R_Process)
  // Saves/restores all action globals; calls BeforeRoutines if defined, then performAction
  static async processActionStatement(
      state: GameState, io: GameIO,
      actionVal: number, nounVal: number, secondVal: number,
      actorVal?: number
  ): Promise<[GameState, InformValue]> {
    const savedAction = getGlobal(state, 'action');
    const savedNoun = getGlobal(state, 'noun');
    const savedSecond = getGlobal(state, 'second');
    const savedInp1 = getGlobal(state, 'inp1');
    const savedInp2 = getGlobal(state, 'inp2');
    const savedActor = getGlobal(state, 'actor');
    state = setGlobal(state, 'action', actionVal);
    state = setGlobal(state, 'noun', nounVal);
    state = setGlobal(state, 'second', secondVal);
    state = setGlobal(state, 'inp1', nounVal);
    state = setGlobal(state, 'inp2', secondVal);
    if (actorVal !== undefined) state = setGlobal(state, 'actor', actorVal);
    const [_brs, _brv] = await Game.invokeRoutine('beforeroutines', state, io, []);
    state = _brs;
    if (toInt(_brv) === 0) {
      const [_as, _] = await Game.performAction(state, io, actionVal);
      state = _as;
    }
    state = setGlobal(state, 'action', savedAction);
    state = setGlobal(state, 'noun', savedNoun);
    state = setGlobal(state, 'second', savedSecond);
    state = setGlobal(state, 'inp1', savedInp1);
    state = setGlobal(state, 'inp2', savedInp2);
    state = setGlobal(state, 'actor', savedActor);
    return [state, intValue(0)];
  }

  // Invoke a property function on an object
  static async invokePropertyFunction(obj: InformValue, propertyName: string, state: GameState, io: GameIO, args: InformValue[]): Promise<[GameState, InformValue] | null> {
    const objectId = toStringId(state, obj);

    const dispatchResult = await Game.dispatchPropertyFunction(objectId, propertyName, state, io, args);
    if (dispatchResult !== null) return dispatchResult;

    const _objDef = state.definition.objects.get(objectId.toLowerCase());
    if (_objDef !== undefined && _objDef.className !== null) {
      const classResult = await Game.dispatchClassPropertyFunction(_objDef.className, propertyName, state, io, args, toInt(obj));
      if (classResult !== null) return classResult;
    }

    if (propertyName.toLowerCase() === 'create' && state.definition.classHierarchy.has(objectId.toLowerCase())) {
      const [newState, newObjNum] = classCreate(state, objectId);
      return [newState, intValue(newObjNum)];
    }

    const objDef = state.definition.objects.get(objectId.toLowerCase());
    if (objDef !== undefined) {
      let pv = state.treeState.getProperty(objectId, propertyName.toLowerCase());
      if (pv === null) pv = objDef.initialProperties.get(propertyName.toLowerCase()) ?? null;
      if (pv !== null) {
        if (pv.kind === 'routine') return await Game.invokeRoutine(pv.routineName, state, io, args);
        if (pv.kind === 'string') { io.print(pv.value); return [state, intValue(1)]; }
        if (pv.kind === 'int' && pv.value === ((-1) | 0)) return [state, intValue(0)];
        if (pv.kind === 'int') return [state, intValue(pv.value)];
        if (pv.kind === 'list') return [state, intValue(pv.values.length > 0 && pv.values[0].kind === 'int' ? pv.values[0].value : 0)];
      }
    }
    // Common property defaults (from Property declarations)
    const _pnl = propertyName.toLowerCase();
    if (_pnl === 'capacity') {
      return [state, intValue(100)];
    } else if (_pnl === 'short_name') {
      return [state, intValue(0)];
    } else if (_pnl === 'short_name_indef') {
      return [state, intValue(0)];
    } else if (_pnl === 'parse_name') {
      return [state, intValue(0)];
    }
    return [state, intValue(0)];
  }

